from typing import List

class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        sum1 = sum(nums1)
        sum2 = sum(nums2)
        zeros1 = nums1.count(0)
        zeros2 = nums2.count(0)

        # If both arrays have no zeros, check if sums are equal
        if zeros1 == 0 and zeros2 == 0:
            return sum1 if sum1 == sum2 else -1

        # If one array has no zeros, the other must have sum >= its sum
        if zeros1 == 0:
            if sum1 < sum2:
                return -1
            # We need to add at least 1 to each zero in nums2
            required = sum2 + zeros2
            if sum1 >= required:
                return required
            else:
                return -1

        if zeros2 == 0:
            if sum2 < sum1:
                return -1
            required = sum1 + zeros1
            if sum2 >= required:
                return required
            else:
                return -1

        # Both arrays have zeros
        # We need to make sum1 + z1 >= sum2 + z2 and sum2 + z2 >= sum1 + z1
        # So the minimal sum is max(sum1 + z1, sum2 + z2)
        return max(sum1 + zeros1, sum2 + zeros2)
